import re

_VALID_VERSIONS = {1, 2, 3}
_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}
_TOKEN_PATTERN = re.compile(r"^[A-Z]+[0-9]+$")
_CHANNEL_PATTERN = re.compile(r"^[a-z][a-z0-9_]*$")


def _token_value(token: str) -> int:
    total = 0
    for ch in token:
        if "A" <= ch <= "Z":
            total += ord(ch) - ord("A") + 1
        elif "0" <= ch <= "9":
            total += 2 * int(ch)
    return total


def _split_payload(payload: str) -> list[str]:
    if payload == "":
        return []
    tokens = payload.split("-")
    if any(t == "" or not _TOKEN_PATTERN.fullmatch(t) for t in tokens):
        raise ValueError("invalid payload")
    return tokens


def _checksum(payload: str, version: int) -> int:
    return sum(_token_value(t) for t in _split_payload(payload)) % _CHECKSUM_MODULUS[version]


def solve(packet: str) -> bool:
    try:
        if not isinstance(packet, str):
            return False

        parts = packet.split("::")
        if len(parts) == 4:
            prefix, version_s, channel, payload = parts
            checksum_s = None
        elif len(parts) == 5:
            prefix, version_s, channel, payload, checksum_s = parts
        else:
            return False

        if prefix != "FXN":
            return False

        if not version_s.isdigit():
            return False
        version = int(version_s)
        if version not in _VALID_VERSIONS:
            return False

        if not _CHANNEL_PATTERN.fullmatch(channel):
            return False

        _split_payload(payload)

        if version == 1 and payload == "" and (checksum_s is None or checksum_s == "" or checksum_s.isdigit()):
            return True

        if checksum_s is None or not checksum_s.isdigit():
            return False

        return int(checksum_s) == _checksum(payload, version)
    except Exception:
        return False

