            break

    if payload is None:
        candidates = []
        for i, part in enumerate(parts):
            if i == version_idx or i == checksum_idx:
                continue
            low = part.lower()
            if re.fullmatch(r"(?:fluxon|fxn|packet|pkt|v[123]|version\s*=?\s*[123])", low):
                continue
            candidates.append((i, part))

        dashed = [(i, p) for i, p in candidates if "-" in p]
        if dashed:
            payload = dashed[-1][1]
        elif checksum_idx is not None and checksum_idx > 0:
            prev = parts[checksum_idx - 1]
            if checksum_idx - 1 != version_idx:
                payload = prev
        elif candidates:
            payload = candidates[-1][1]
        else:
            payload = ""

    payload = clean(payload)

    if version == 1 and payload == "":
        return True

    if checksum is None or checksum < 0:
        return False

    if payload == "":
        tokens = []
    else:
