            return ord(c) - ord("A") + 1

        def base36(c: str) -> int:
            if c.isdigit():
                return int(c)
            return ord(c) - ord("A") + 10

        vals = [
            sum(ord(c) for c in token),
            sum(alpha1(c) for c in u),
            sum(base36(c) for c in u),
            sum((i + 1) * ord(c) for i, c in enumerate(token)),
            sum((i + 1) * alpha1(c) for i, c in enumerate(u)),
            sum((i + 1) * base36(c) for i, c in enumerate(u)),
        ]

        if token.isdigit():
            vals.append(int(token))

        return tuple(dict.fromkeys(vals))

    totals = {0}
    for tok in tokens:
        totals = {a + b for a in totals for b in values(tok)}

    return any(total % mod == checksum for total in totals)

