_TOKEN_PATTERN = re.compile(r"^[A-G][0-9]$")
_VALID_VERSIONS = {1, 2, 3}
_CHECKSUM_MODULUS = {1: 89, 2: 97, 3: 113}


def token_value(token: str) -> int:
    if not _TOKEN_PATTERN.match(token):
        raise ValueError(f"Invalid Fluxon token: {token!r}")
    return (ord(token[0]) - ord("A") + 1) * 10 + int(token[1])


def split_fluxon_payload(payload: str) -> list[str]:
    if payload == "":
        return []
    tokens = payload.split("-")
    for token in tokens:
        if not _TOKEN_PATTERN.match(token):
            raise ValueError(f"Invalid Fluxon token: {token!r}")
    return tokens


def compute_fluxon_checksum(payload: str, version: int) -> int:
    if version not in _VALID_VERSIONS:
        raise ValueError(f"Invalid version: {version}")
    return sum(token_value(token) for token in split_fluxon_payload(payload)) % _CHECKSUM_MODULUS[version]


def parse_fluxon_packet(packet: str) -> dict:
    parts = packet.split("::")
    if len(parts) != 5 or parts[0] != "FXN":
        raise ValueError(f"Invalid Fluxon packet: {packet!r}")

    try:
        version = int(parts[1])
    except ValueError:
        raise ValueError(f"Invalid version: {parts[1]!r}")

    if version not in _VALID_VERSIONS:
        raise ValueError(f"Invalid version: {version}")

    channel = parts[2]
    if channel not in {"alpha", "beta", "gamma"}:
        raise ValueError(f"Invalid channel: {channel!r}")

    payload = parts[3]
    tokens = split_fluxon_payload(payload)

    try:
        checksum = int(parts[4])
    except ValueError:
        raise ValueError(f"Invalid checksum: {parts[4]!r}")

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "tokens": tokens,
        "checksum": checksum,
    }


