    rec1 = parse_fluxon_packet(packet1)
    rec2 = parse_fluxon_packet(packet2)

    merged_version = max(rec1["version"], rec2["version"])
    payloads = [rec1["payload"], rec2["payload"]]
    merged_payload = "-".join(payloads) if any(payloads) else ""

    return compute_fluxon_checksum(merged_payload, merged_version)

