        packet = _decode_fluxon_frame(frame)
        parts = packet.split("::")

        if len(parts) == 3:
            if parts[0] != "FXN" or parts[1] != "1" or parts[2] != "":
                return -1
            return 0

        if len(parts) not in (4, 5):
            return -1

        if parts[0] != "FXN" or parts[1] not in ("1", "2", "3"):
            return -1

        version = int(parts[1])
        payload = parts[-2]
        checksum_text = parts[-1]

