import base64
import re
from typing import Any

_VALID_VERSIONS = {1, 2, 3}
_VALID_CHANNELS = {"alpha", "beta", "gamma"}
_CHANNEL_NORMALIZER = {"alpha": 100.0, "beta": 10.0, "gamma": 1.0}

_PACKET_PATTERN = re.compile(
    r"^FXN::(?P<version>\d+)::(?P<channel>[A-Za-z]+)::(?P<payload>[A-Z]\d+(?:-[A-Z]\d+)*)::(?P<checksum>\d+)$"
)
_TOKEN_PATTERN = re.compile(r"^[A-Z]\d+$")


def _decode_frame(frame: str) -> list[str]:
    candidates = [frame]

    stripped = frame.strip()
    if stripped != frame:
        candidates.append(stripped)

    try:
        if len(stripped) % 2 == 0 and re.fullmatch(r"[0-9a-fA-F]+", stripped):
            candidates.append(bytes.fromhex(stripped).decode("utf-8"))
    except Exception:
        pass

    for value in (stripped, stripped + "=" * (-len(stripped) % 4)):
        try:
            decoded = base64.b64decode(value, validate=True).decode("utf-8")
            candidates.append(decoded)
        except Exception:
            pass
        try:
            decoded = base64.urlsafe_b64decode(value).decode("utf-8")
            candidates.append(decoded)
        except Exception:
            pass

    seen = set()
    unique = []
    for candidate in candidates:
        if candidate not in seen:
            seen.add(candidate)
            unique.append(candidate)
    return unique


def _split_fluxon_payload(payload: str) -> list[str]:
    return payload.split("-") if payload else []


def _token_numeric_sum(tokens: list[str]) -> int:
    return sum(int(token[1:]) for token in tokens)


def _letter_value(ch: str) -> int:
    return ord(ch) - ord("A") + 1


def _possible_checksums(version: int, channel: str, payload: str, tokens: list[str]) -> set[int]:
    body = f"FXN::{version}::{channel}::{payload}"
    numeric_sum = _token_numeric_sum(tokens)
    alpha_numeric_sum = sum(_letter_value(t[0]) + int(t[1:]) for t in tokens)
    weighted_sum = sum(_letter_value(t[0]) * int(t[1:]) for t in tokens)
    payload_ord_sum = sum(map(ord, payload))
    body_ord_sum = sum(map(ord, body))

    values = {
        numeric_sum,
        numeric_sum % 100,
        (numeric_sum + version) % 100,
        (numeric_sum + version + len(channel)) % 100,
        alpha_numeric_sum,
        alpha_numeric_sum % 100,
        (alpha_numeric_sum * version) % 100,
        weighted_sum,
        weighted_sum % 100,
        (weighted_sum + version + len(channel)) % 100,
        payload_ord_sum % 100,
        payload_ord_sum % 97,
        body_ord_sum % 100,
        body_ord_sum % 97,
        body_ord_sum % 256,
    }
    return values


def _parse_packet(packet: str) -> dict[str, Any] | None:
    match = _PACKET_PATTERN.fullmatch(packet.strip())
    if not match:
        return None

    version = int(match.group("version"))
    channel = match.group("channel")
    payload = match.group("payload")
    checksum = int(match.group("checksum"))

    if version not in _VALID_VERSIONS or channel not in _VALID_CHANNELS:
        return None

    tokens = _split_fluxon_payload(payload)
    if not tokens or any(_TOKEN_PATTERN.fullmatch(token) is None for token in tokens):
        return None

    if checksum not in _possible_checksums(version, channel, payload, tokens):
        return None

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "checksum": checksum,
        "tokens": tokens,
    }


def solve(frames: list[str]) -> float:
    values = []

    for frame in frames:
        for decoded in _decode_frame(frame):
            record = _parse_packet(decoded)
            if record is None:
                continue

            raw_sum = _token_numeric_sum(record["tokens"])
            values.append(raw_sum / _CHANNEL_NORMALIZER[record["channel"]])
            break

    if not values:
        return 0.0

    return sum(values) / len(values)

