    value = value.strip()
    if "=" in value:
        value = value.split("=", 1)[1].strip()
    return value


def _parse_version(value: str) -> int | None:
    value = _strip_label(value)
    m = re.fullmatch(r"(?i)v(?:ersion)?\s*([123])", value)
    if m:
        return int(m.group(1))
    m = re.fullmatch(r"[^\d]*([123])[^\d]*", value)
