    tokens = payload.split("-")
    if any(not _TOKEN_PATTERN.match(token) for token in tokens):
        raise ValueError("Invalid Fluxon payload")
    return tokens


def _token_value(token: str) -> int:
    if not _TOKEN_PATTERN.match(token):
        raise ValueError("Invalid Fluxon token")
    return (ord(token[0]) - ord("A") + 1) * 10 + int(token[1])


def _checksum_for_tokens(tokens: list[str], version: int) -> int:
    if version not in _VALID_VERSIONS:
        raise ValueError("Invalid version")
    return sum(_token_value(token) for token in tokens) % _CHECKSUM_MODULUS[version]


def _parse_fluxon_packet(packet: str | dict[str, Any]) -> dict[str, Any]:
    if isinstance(packet, dict):
        version = int(packet["version"])
        payload = packet.get("payload", "")
        checksum = int(packet["checksum"])
        tokens = packet.get("tokens")
        if tokens is None:
            tokens = _split_fluxon_payload(payload)
        else:
            tokens = list(tokens)
            if any(not _TOKEN_PATTERN.match(token) for token in tokens):
                raise ValueError("Invalid Fluxon token")
            payload = "-".join(tokens)
        if version not in _VALID_VERSIONS:
            raise ValueError("Invalid version")
