    try:
        record = _parse_fluxon_packet(packet)
        expected = _checksum_for_tokens(record["tokens"], record["version"])
        if record["version"] == 1 and record["payload"] == "":
            return True
        return record["checksum"] == expected
    except Exception:
        return False


