import re
from typing import Any

_TOKEN_PATTERN = re.compile(r"^[A-G][0-9]$")


def _split_fluxon_payload(payload: str) -> list[str]:
    if payload == "":
        return []
    return payload.split("-")


def _token_value(token: str) -> int:
    if not _TOKEN_PATTERN.match(token):
        raise ValueError(f"Invalid Fluxon token: {token!r}")
    return (ord(token[0]) - ord("A") + 1) * 10 + int(token[1])


def _compute_fluxon_checksum(payload: str, version: int) -> int:
    tokens = _split_fluxon_payload(payload)
    total = sum((i + 1) * _token_value(token) for i, token in enumerate(tokens))
    return total % (97 if version == 1 else 997)


def _split_record_fields(s: str) -> list[str]:
    fields = []
    cur = []
    escaped = False
    for ch in s:
        if escaped:
            cur.append(ch)
            escaped = False
        elif ch == "\\":
            escaped = True
        elif ch == ",":
            fields.append("".join(cur))
            cur = []
        else:
            cur.append(ch)
    if escaped:
        cur.append("\\")
    fields.append("".join(cur))
    return fields


def _parse_fluxon_packet(packet: str) -> dict[str, Any]:
    if not isinstance(packet, str):
        raise ValueError("packet must be a string")
    s = packet.strip()
    if s.startswith("FXR[") and s.endswith("]"):
        s = s[4:-1]
    if "|" in s:
        parts = s.split("|")
        if len(parts) != 1:
            raise ValueError("expected one record")
        s = parts[0]

    fields = _split_record_fields(s)
    if len(fields) != 4:
        raise ValueError("expected four fields")

    version = int(fields[0])
    channel = fields[1]
    payload = fields[2]
    checksum = int(fields[3])
    tokens = _split_fluxon_payload(payload)

    for token in tokens:
        if not _TOKEN_PATTERN.match(token):
            raise ValueError(f"invalid token: {token!r}")

    return {
        "version": version,
        "channel": channel,
        "payload": payload,
        "checksum": checksum,
        "tokens": tokens,
    }


