    return payload.split("-")


def _checksum(payload: str, version: int) -> int:
    if version not in _VALID_VERSIONS:
        raise ValueError("invalid version")
    return sum(_token_value(t) for t in _split_payload(payload)) % _MODULUS[version]


def _parse_version(s: str) -> int | None:
    s = s.strip()
    if re.fullmatch(r"[vV]?[123]", s):
        return int(s[-1])
    m = re.search(r"(?:^|[^0-9A-Za-z])(?:v|version)?\s*=?\s*([123])(?:$|[^0-9A-Za-z])", s, re.I)
    if m:
        return int(m.group(1))
    return None


def _payload_ok(payload: str) -> bool:
    try:
