                version_idx = -1
                for i, part in enumerate(parts[:-1]):
                    version = _parse_version(part)
                    if version is not None:
                        version_idx = i
                        break
                if version is None:
                    continue

                payload_idx = None
                for i in range(len(parts) - 2, -1, -1):
                    if i != version_idx and _looks_like_payload(parts[i].strip()):
                        payload_idx = i
                        break
                if payload_idx is None:
