    if not nums:
        raise ValueError("missing checksum")
    checksum = int(nums[-1].group(0))

    if not _payload_ok(payload):
        raise ValueError("invalid payload")

    return {
        "version": version,
        "payload": payload,
        "checksum": checksum,
        "tokens": _split_payload(payload),
